public InflectionRule(string pattern, string replacement)
{
    // Avoid RegexOptions.Compiled for many short-lived rules — the JIT compilation
    // cost (100-500ms for 40-60 rules) far outweighs the per-match savings on
    // short strings. The regex cache handles interpreted patterns efficiently.
    _regex = new Regex(pattern, RegexOptions.IgnoreCase);
    _replacement = replacement;
}

/// <summary>
/// Attempts to apply this rule to the given word.
/// </summary>
/// <param name="word">The word to transform.</param>
/// <returns>The transformed word if the pattern matches; otherwise, null.</returns>
public string? Apply(string word)
{
    // Use a single Replace call instead of IsMatch + Replace to avoid
    // evaluating the regex twice for matching inputs.
    var result = _regex.Replace(word, _replacement);
    return string.Equals(result, word, StringComparison.Ordinal) ? null : result;
}

